<?php ao_schema_ensure_v1500(); $products=db()->query('SELECT * FROM license_products ORDER BY name')->fetchAll(); $plans=db()->query('SELECT lp.*, p.name product_name FROM license_plans lp LEFT JOIN license_products p ON p.id=lp.product_id ORDER BY lp.id DESC')->fetchAll(); ?>
<div class="ao-card"><h2>Lisans Planları</h2><form method="post" action="<?= url('admin/license-center/plan-save') ?>"><?= csrf_field() ?><div class="ao-form-grid"><label>Ürün<select name="product_id"><?php foreach($products as $p): ?><option value="<?= (int)$p['id'] ?>"><?= e($p['name']) ?></option><?php endforeach; ?></select></label><label>Plan Adı<input name="name" value="Tek Kullanımlık Lisans"></label><label>Lisans Tipi<select name="license_type"><option value="single_use">Tek Kullanımlık</option><option value="domain_lifetime">Domain Bazlı</option><option value="device">Cihaz Bazlı</option><option value="subscription">Süreli</option><option value="open_source">Açık Kaynak</option></select></label><label>Süre Gün<input type="number" name="duration_days" value="0"></label><label>Max Domain<input type="number" name="max_domains" value="1"></label><label>Max Cihaz<input type="number" name="max_devices" value="1"></label><label>Fiyat<input type="number" step="0.01" name="price" value="499"></label><label>Para Birimi<input name="currency" value="TRY"></label><label><input type="checkbox" name="is_open_source" value="1"> Açık kaynak / lisanssız</label></div><button class="ao-btn">Plan Ekle</button></form></div>
<div class="ao-card"><h3>Plan Listesi</h3><table class="ao-table"><tr><th>Ürün</th><th>Plan</th><th>Tip</th><th>Fiyat</th><th>Durum</th></tr><?php foreach($plans as $p): ?><tr><td><?= e($p['product_name']) ?></td><td><?= e($p['name']) ?></td><td><?= e($p['license_type']) ?></td><td><?= e($p['price'].' '.$p['currency']) ?></td><td><?= e($p['status']) ?></td></tr><?php endforeach; ?></table></div>
